bool
pgcopydb_sql_list_source_indexes(int filter,
								 const char **sql)
{
	switch (filter)
	{
		case 0: /* no-filter */
		{
			*sql = sql__list_source_indexes__no_filter__default;
			return true;
		}

		case 1: /* incl */
		{
			*sql = sql__list_source_indexes__incl__default;
			return true;
		}

		case 2: /* excl */
		{
			*sql = sql__list_source_indexes__excl__default;
			return true;
		}

		case 3: /* list-not-incl */
		{
			*sql = sql__list_source_indexes__list_not_incl__default;
			return true;
		}

		case 4: /* list-excl */
		{
			*sql = sql__list_source_indexes__list_excl__default;
			return true;
		}

		case 5: /* excl-index */
		{
			*sql = sql__list_source_indexes__excl_index__default;
			return true;
		}

		case 6: /* list-excl-index */
		{
			*sql = sql__list_source_indexes__list_excl_index__default;
			return true;
		}

		default:
		{
			break;
		}
	}
	return false;
}


